def gen(rng, size):
    n = rng.randint(2, max(2, size))
    rooms = [[] for _ in range(n)]
    # sometimes guarantee full reachability via a chain, sometimes don't
    if rng.random() < 0.5:
        for i in range(n - 1):
            rooms[i].append(i + 1)
    for i in range(n):
        extra = rng.randint(0, 3)
        for _ in range(extra):
            k = rng.randrange(n)
            if k not in rooms[i]:
                rooms[i].append(k)
    return [rooms]

