class Solution:
    def canVisitAllRooms(self, rooms):
        n = len(rooms)
        # iterative fixpoint: repeatedly absorb keys until nothing new opens
        have = {0}
        changed = True
        while changed:
            changed = False
            for r in list(have):
                for k in rooms[r]:
                    if k not in have:
                        have.add(k)
                        changed = True
        return len(have) == n

