class Solution:
    def canVisitAllRooms(self, rooms):
        n = len(rooms)
        seen = [False] * n
        seen[0] = True
        stack = [0]
        count = 1
        while stack:
            r = stack.pop()
            for k in rooms[r]:
                if not seen[k]:
                    seen[k] = True
                    count += 1
                    stack.append(k)
        return count == n

solutions.javascript:
var canVisitAllRooms = function(rooms) {
    const n = rooms.length;
    const seen = new Array(n).fill(false);
    seen[0] = true;
    const stack = [0];
    let count = 1;
    while (stack.length) {
        const r = stack.pop();
        for (const k of rooms[r]) {
            if (!seen[k]) {
                seen[k] = true;
                count++;
                stack.push(k);
            }
        }
    }
    return count === n;
};
